function start_template(){
//	var tTH = new TaskTemplateHelpers();
//	var fields = tTH.createEmptyTemplateFieldsJSON();
//	for(var field in fields){
//		fields[field].value = current.getValue(field);
//	}
//	var templateInputs = {};
//	templateInputs = tTH.loadTemplateInputsFromDataFields(fields);	
//	tTH.startTemplateWithID(current.routing_template_ref, true, templateInputs);

	var ga = new GlideAjax("ClientTaskTemplateHelpers");
	ga.addParam('sysparm_name', 'createEmptyTemplateFieldsJSON');
	ga.getXML(function (response) {
		try {
			var oFields = JSON.parse(response.responseXML.documentElement.getAttribute('answer'));
			for(var field in oFields){
				oFields[field].value = g_form.getValue(field);
			}
			var ga = new GlideAjax("ClientTaskTemplateHelpers");
			ga.addParam('sysparm_name', 'loadTemplateInputsFromDataFields');
			ga.addParam('fields',JSON.stringify(oFields));
			ga.getXML(function (response) {
				try {
					var templateInputs = JSON.parse(response.responseXML.documentElement.getAttribute('answer'));
					var ga = new GlideAjax("ClientTaskTemplateHelpers");
					ga.addParam('sysparm_name', 'startTemplateWithID');
					ga.addParam('templateInputs',JSON.stringify(templateInputs));
					ga.addParam('template',g_form.getValue('routing_template_ref'));
					ga.getXML(function (response) {
						try {
							g_form.addInfoMessage('Success! Tasker is starting the selected template.');
						} catch(e) {
							jslog(e);
						}
					});
				} catch(e) {
					jslog(e);
				}
			});
		} catch(e) {
			jslog(e);
		}
	});
	return true;
}
